# Unit Tests for `fizzbuzz`

```python
import pytest
from mymodule import fizzbuzz  # adjust import to your module path


class TestFizzBuzzHappyPath:
    """Tests for the standard, expected behavior of fizzbuzz."""

    @pytest.mark.parametrize("n", [3, 6, 9, 12, 18, 21, 24, 27])
    def test_multiples_of_3_only_return_fizz(self, n):
        assert fizzbuzz(n) == "Fizz"

    @pytest.mark.parametrize("n", [5, 10, 20, 25, 35, 40, 50])
    def test_multiples_of_5_only_return_buzz(self, n):
        assert fizzbuzz(n) == "Buzz"

    @pytest.mark.parametrize("n", [15, 30, 45, 60, 75, 90, 150])
    def test_multiples_of_15_return_fizzbuzz(self, n):
        assert fizzbuzz(n) == "FizzBuzz"

    @pytest.mark.parametrize("n,expected", [
        (1, "1"),
        (2, "2"),
        (4, "4"),
        (7, "7"),
        (8, "8"),
        (11, "11"),
        (13, "13"),
        (14, "14"),
        (16, "16"),
        (17, "17"),
    ])
    def test_non_multiples_return_string_of_number(self, n, expected):
        assert fizzbuzz(n) == expected


class TestFizzBuzzEdgeCases:
    """Tests for edge cases such as zero, negatives, and large numbers."""

    def test_zero_returns_fizzbuzz(self):
        # 0 % 15 == 0, so this hits the FizzBuzz branch
        assert fizzbuzz(0) == "FizzBuzz"

    @pytest.mark.parametrize("n,expected", [
        (-3, "Fizz"),
        (-6, "Fizz"),
        (-9, "Fizz"),
        (-5, "Buzz"),
        (-10, "Buzz"),
        (-15, "FizzBuzz"),
        (-30, "FizzBuzz"),
        (-1, "-1"),
        (-2, "-2"),
        (-7, "-7"),
    ])
    def test_negative_numbers(self, n, expected):
        assert fizzbuzz(n) == expected

    def test_large_multiple_of_15(self):
        assert fizzbuzz(15_000_000) == "FizzBuzz"

    def test_large_multiple_of_3(self):
        assert fizzbuzz(3_000_001 * 3) == "Fizz"

    def test_large_multiple_of_5(self):
        # 5_000_002 * 5 = 25_000_010, divisible by 5 but not by 3
        assert fizzbuzz(5_000_002 * 5) == "Buzz"

    def test_large_non_multiple(self):
        # 10_000_001 is not divisible by 3 or 5
        assert fizzbuzz(10_000_001) == "10000001"

    def test_return_type_is_always_string(self):
        for n in [0, 1, 3, 5, 15, -7, 100]:
            assert isinstance(fizzbuzz(n), str)


class TestFizzBuzzPriority:
    """Tests that confirm the 15-check is evaluated before 3 or 5."""

    def test_15_takes_precedence_over_3(self):
        # 15 is divisible by 3, but should not return "Fizz"
        assert fizzbuzz(15) != "Fizz"
        assert fizzbuzz(15) == "FizzBuzz"

    def test_15_takes_precedence_over_5(self):
        # 15 is divisible by 5, but should not return "Buzz"
        assert fizzbuzz(15) != "Buzz"
        assert fizzbuzz(15) == "FizzBuzz"


class TestFizzBuzzErrorCases:
    """Tests for invalid input types that should raise errors."""

    @pytest.mark.parametrize("bad_input", [
        "5",
        "fifteen",
        None,
        [3],
        {15},
        (5,),
        object(),
    ])
    def test_non_int_non_numeric_raises_type_error(self, bad_input):
        with pytest.raises(TypeError):
            fizzbuzz(bad_input)

    def test_float_multiple_of_15_does_not_raise(self):
        # Note: floats actually work with %, so this documents current behavior.
        # 15.0 % 15 == 0.0, so fizzbuzz(15.0) returns "FizzBuzz".
        assert fizzbuzz(15.0) == "FizzBuzz"

    def test_float_non_multiple_returns_str_of_float(self):
        # Documents that floats leak through and get str()'d
        assert fizzbuzz(2.5) == "2.5"

    def test_bool_true_behaves_as_1(self):
        # In Python, bool is a subclass of int: True == 1
        assert fizzbuzz(True) == "1"

    def test_bool_false_behaves_as_0(self):
        # False == 0, which is divisible by 15
        assert fizzbuzz(False) == "FizzBuzz"
